```java
public class Main {
    public static void main(String[] args) {
        boolean[] inputArray = {true, false, true, true, false};
        int sum = calculateSum(inputArray);
        System.out.println("Sum: " + sum);
    }

    public static int calculateSum(boolean[] arr) {
        int sum = 0;
        for (boolean value : arr) {
            if (value) {
                sum++;
            }
        }
        return sum;
    }
}
